pseudocode:
GIVEN
  // Arrange
  Attribute attr = new Attribute("key", "value", null);

WHEN
  Range.AttributeRange range = attr.sourceRange();
THEN
  assert range == Range.AttributeRange.UntrackedAttr;

GIVEN
  // Arrange
  Range.AttributeRange expected = new Range.AttributeRange(1,2,3,4);
  Attributes stubParent = new Attributes(){ @Override public Range.AttributeRange sourceRange(String k){ return expected; }};
  Attribute attr = new Attribute("key", "value", stubParent);

WHEN
  Range.AttributeRange range = attr.sourceRange();
THEN
  assert range == expected;
